/* PasstheEPPP — Question Bank Batch 48
   90 new questions — Final batch to reach 2000+ — all domains */
(function(){
    if (typeof EPPPData === 'undefined') return;

    const batch48 = [
        // === Ethics (10) ===
        {domainId:8, q:"Supervision ethics require that supervisors:", options:["Take credit for all of the supervisee's clinical and academic work products as their own","Provide adequate oversight, give honest feedback, ensure competence, and take responsibility for quality","Allow supervisees to practice independently without any structured oversight or evaluation","Avoid establishing any professional relationship or ongoing contact with their assigned supervisees"], answer:1, difficulty:"medium", rationale:"Correct: (B) Ethical supervision: monitor supervisees' work, provide constructive feedback, model ethical behavior, maintain appropriate boundaries, ensure supervisees practice within their competence, and take responsibility for client welfare under supervision.\n\nWhy others are wrong:\n(A) Credit should be fairly attributed to the supervisee.\n(C) Adequate oversight is legally and ethically required.\n(D) The supervisory relationship is necessary for professional development."},
        {domainId:8, q:"Plagiarism in academic and scientific work is:", options:["Acceptable if the copying was completely unintentional and occurred due to careless note-taking","A violation of APA Standard 8.11 presenting portions of another's work or data as one's own","Only relevant for students and trainees and does not apply to licensed professional psychologists","Permitted as long as the author provides a brief verbal citation during professional presentations"], answer:1, difficulty:"easy", rationale:"Correct: (B) APA Standard 8.11: psychologists do not present portions of another's work or data as their own, even unintentionally. Proper attribution is required. Publication credit must reflect actual contributions (Standard 8.12).\n\nWhy others are wrong:\n(A) Unintentional plagiarism is still plagiarism — due diligence is expected.\n(C) The standard applies to ALL psychologists, not just students.\n(D) Proper written citation is required, not just verbal mention."},
        {domainId:8, q:"Emergency situations create an exception to:", options:["All ethical standards universally without any restrictions on the scope of the professional's actions","The requirement for informed consent — psychologists may provide emergency services without standard procedures","All principles of good clinical practice including the duty to provide competent professional care","All confidentiality rules permanently and irrevocably for the remainder of the professional relationship"], answer:1, difficulty:"medium", rationale:"Correct: (B) In emergencies (suicidal crisis, immediate danger), psychologists can act to protect life without full informed consent. Once the emergency passes, standard procedures resume. This exception is narrow and time-limited.\n\nWhy others are wrong:\n(A) Emergency doesn't suspend ALL ethics — just specific procedural requirements.\n(C) Good clinical practice is maintained even in emergencies.\n(D) Confidentiality limits in emergencies are specific and proportional."},
        {domainId:8, q:"APA Standard 2.06 addresses personal problems. Psychologists should:", options:["Continue practicing at full capacity regardless of any personal difficulties affecting their functioning","Refrain from activities when personal problems might compromise competence and harm those they serve","Never experience any personal problems as a condition of maintaining their professional licensure","Only take breaks from clinical practice during pre-scheduled annual vacation periods from the office"], answer:1, difficulty:"easy", rationale:"Correct: (B) Standard 2.06: when psychologists become aware of personal problems (health, emotional, substance) that could compromise their professional functioning, they should take appropriate measures (consult, limit activities, seek help).\n\nWhy others are wrong:\n(A) Practicing while impaired risks harming clients.\n(C) Having personal problems is human — the obligation is to manage their impact.\n(D) Self-monitoring should be continuous, not limited to scheduled breaks."},
        {domainId:8, q:"Authorship credit on publications should be based on:", options:["Seniority and academic rank within the department regardless of actual contributions to the work","Substantial professional contributions to the design, analysis, interpretation, or writing of the work","Being employed in the same academic department or institutional affiliation as the primary researcher","Providing financial funding for the research regardless of intellectual contribution to the project"], answer:1, difficulty:"easy", rationale:"Correct: (B) APA Standard 8.12: authorship reflects actual scientific or professional contributions (design, analysis, writing). Administrative contributions alone don't warrant authorship. Order reflects contribution magnitude.\n\nWhy others are wrong:\n(A) Seniority doesn't automatically warrant authorship.\n(C) Department affiliation is insufficient for authorship credit.\n(D) Funding alone doesn't justify authorship — though it may warrant acknowledgment."},
        {domainId:8, q:"When a psychologist closes their practice (retirement, relocation), they must:", options:["Destroy all client records immediately upon the closing date without retaining any backup copies","Provide reasonable notice, ensure continuity of care through appropriate referrals, and arrange record storage","Abandon current clients without any advance notification or assistance with transition planning","Transfer all clients to another provider automatically without obtaining informed consent from clients"], answer:1, difficulty:"medium", rationale:"Correct: (B) Closing a practice: provide reasonable advance notice, assist with transition, make appropriate referrals, ensure records are properly stored/transferred per retention requirements, and handle any clinical emergencies during the transition.\n\nWhy others are wrong:\n(A) Records must be retained according to state requirements.\n(C) Abandonment is unethical and potentially actionable.\n(D) Clients must be informed and consent to transfers."},
        {domainId:8, q:"Using deception in research is:", options:["Always completely prohibited under all circumstances without any allowable exceptions in any study","Permitted when justified by scientific value, no non-deceptive alternatives exist, and no severe harm expected","Required as a mandatory component in all psychological research studies involving human participants","Applicable only in animal research studies and is never permissible in studies with human participants"], answer:1, difficulty:"medium", rationale:"Correct: (B) APA Standard 8.07: deception is acceptable when: (1) justified by prospective value, (2) non-deceptive alternatives don't exist, (3) participants are not expected to experience pain or severe distress, (4) debriefing occurs as soon as possible.\n\nWhy others are wrong:\n(A) Deception is permitted under specific conditions.\n(C) Deception should only be used when necessary.\n(D) These standards govern human participants research."},
        {domainId:8, q:"The Nuremberg Code (1947) established:", options:["The American Psychological Association's specific professional code of ethical conduct and standards","The foundational principles of ethical human research including voluntary consent as absolutely essential","Only military-specific ethics applicable exclusively to armed forces medical and research personnel","Only medical treatment ethics without any application to behavioral or psychological research studies"], answer:1, difficulty:"medium", rationale:"Correct: (B) Following Nazi medical experiments, the Nuremberg Code established: voluntary consent is essential, research should benefit society, unnecessary suffering must be avoided, death/injury should not be expected, and participants can withdraw at any time.\n\nWhy others are wrong:\n(A) APA's code came later (1953) and was independently developed.\n(C) The principles are universal, not limited to military.\n(D) The Code specifically addresses research ethics, not treatment."},
        {domainId:8, q:"Managed care creates ethical challenges because:", options:["It uniformly improves every aspect of clinical care quality without creating any ethical tensions at all","It may limit treatment options, create conflicts between cost containment and client welfare considerations","It has absolutely no effect on ethical practice or clinical decision-making for practicing psychologists","It only affects hospital-based psychologists and has no impact on outpatient private practice settings"], answer:1, difficulty:"medium", rationale:"Correct: (B) Managed care ethical tensions: limited sessions may be insufficient, treatment decisions influenced by cost rather than clinical need, required disclosure of diagnoses to third parties, and psychologists may feel pressure to undertreat or underdiagnose.\n\nWhy others are wrong:\n(A) Managed care creates specific ethical tensions.\n(C) Managed care directly impacts ethical practice considerations.\n(D) Managed care affects all practice settings, not just hospitals."},
        {domainId:8, q:"Social media ethics for psychologists include:", options:["Freely posting about client cases and treatment progress on personal and professional social media accounts","Maintaining appropriate boundaries, avoiding dual relationships, and never disclosing client information online","Accepting all incoming social media friend requests and connection invitations from current therapy clients","Providing psychotherapy services through social media platforms without any established clinical protocols"], answer:1, difficulty:"easy", rationale:"Correct: (B) Social media: maintain professional boundaries, don't search for client information online, address social media in informed consent, avoid dual relationships (friending clients), and never disclose identifying client information on any platform.\n\nWhy others are wrong:\n(A) Posting about clients violates confidentiality.\n(C) Friending clients creates dual relationships.\n(D) Any therapy via technology requires proper procedures and platforms."},

        // === Clinical (15) ===
        {domainId:7, q:"The positive symptoms of schizophrenia include:", options:["Flat affect, alogia, avolition, and anhedonia representing diminished emotional and motivational functioning","Hallucinations, delusions, disorganized speech, and grossly disorganized or catatonic behavioral patterns","Only negative symptom dimensions without any excess or distortion of normal psychological functioning","Only cognitive symptom dimensions such as impaired attention, working memory, and executive functioning"], answer:1, difficulty:"easy", rationale:"Correct: (B) Positive symptoms represent an EXCESS or distortion of normal functioning: hallucinations (usually auditory), delusions (persecutory, grandiose, referential), disorganized speech (derailment, word salad), and grossly disorganized or catatonic behavior.\n\nWhy others are wrong:\n(A) Flat affect/alogia are NEGATIVE symptoms.\n(C)(D) Schizophrenia has positive, negative, and cognitive symptom dimensions."},
        {domainId:7, q:"Generalized Anxiety Disorder (GAD) requires:", options:["Recurrent unexpected panic attacks with persistent worry about having additional panic episodes","Excessive worry about multiple events occurring MORE DAYS THAN NOT for at least six months","Only a specific circumscribed phobia of a particular object or well-defined situational trigger","Brief transient episodes of worry lasting only a few hours without any persistent duration criteria"], answer:1, difficulty:"easy", rationale:"Correct: (B) GAD: excessive, difficult-to-control worry about multiple domains (health, finances, work, family) more days than not for ≥6 months. Plus ≥3 of: restlessness, fatigue, concentration difficulty, irritability, muscle tension, sleep disturbance.\n\nWhy others are wrong:\n(A) Panic attacks → Panic Disorder.\n(C) Specific objects/situations → Specific Phobia.\n(D) The worry must be persistent (≥6 months), not brief."},
        {domainId:7, q:"Delusional Disorder differs from Schizophrenia primarily because:", options:["There are no delusions present and the individual's reality testing remains entirely intact","Non-bizarre delusions are present but functioning apart from the delusion is relatively well preserved","It involves prominent persistent hallucinations as the primary clinical feature without any delusions","It is always a temporary and self-limiting condition that resolves spontaneously within a few days"], answer:1, difficulty:"medium", rationale:"Correct: (B) Delusional Disorder: ≥1 month of delusion(s), generally non-bizarre (could theoretically occur — being followed, poisoned, infected, loved from afar). Functioning is NOT markedly impaired apart from the delusion.\n\nWhy others are wrong:\n(A) Delusions ARE the core feature.\n(C) Hallucinations, if present, are not prominent.\n(D) It lasts at least 1 month and can be chronic."},
        {domainId:7, q:"Oppositional Defiant Disorder (ODD) is characterized by:", options:["Serious violations of the basic rights of others including aggression, destruction, and deceitfulness","Angry/irritable mood, argumentative/defiant behavior, and vindictiveness WITHOUT serious conduct violations","Prominent psychotic symptoms including auditory hallucinations, delusions, and disorganized thinking","Onset exclusively occurring after age 18 during early adulthood developmental transition periods"], answer:1, difficulty:"easy", rationale:"Correct: (B) ODD: angry/irritable mood, argumentative/defiant behavior, vindictiveness — but does NOT include serious aggression, destruction, theft, or deceitfulness (which would suggest Conduct Disorder).\n\nWhy others are wrong:\n(A) Serious rights violations → Conduct Disorder.\n(C) ODD has no psychotic features.\n(D) ODD typically emerges in childhood; cannot be first diagnosed after 18."},
        {domainId:7, q:"Brief Psychotic Disorder lasts:", options:["At least six months meeting the full duration criteria required for a schizophrenia spectrum diagnosis","At least one day but less than one month with eventual full return to premorbid level of functioning","At least one full calendar year with persistent psychotic symptoms throughout the entire duration","Permanently without any possibility of symptom remission or return to baseline functioning level"], answer:1, difficulty:"easy", rationale:"Correct: (B) Brief Psychotic Disorder: duration ≥1 day but <1 month, with full return to premorbid functioning. If >1 month but <6 months → Schizophreniform. If >6 months → Schizophrenia.\n\nWhy others are wrong:\n(A) ≥6 months duration → consider Schizophrenia.\n(C) ≥1 year is beyond the brief psychotic window.\n(D) Recovery to premorbid functioning is required."},
        {domainId:7, q:"Anorexia Nervosa, restrictive subtype involves:", options:["Recurrent episodes of binge eating followed by self-induced vomiting or laxative compensatory purging","Food restriction leading to significantly low body weight achieved without any binge-purge behaviors","Only excessive compulsive exercise without any restriction of caloric food intake or dietary patterns","Completely normal and adequate eating patterns with no restriction, bingeing, or compensatory behaviors"], answer:1, difficulty:"easy", rationale:"Correct: (B) AN restricting: weight loss achieved through dieting, fasting, and/or excessive exercise WITHOUT binge eating or purging. The binge-eating/purging subtype involves restriction PLUS binge-purge episodes.\n\nWhy others are wrong:\n(A) Binge eating and purging is the binge-eating/purging subtype of AN or Bulimia Nervosa.\n(C) Exercise can be a component but restriction includes food intake limitation.\n(D) AN by definition involves abnormal food restriction."},
        {domainId:7, q:"The DSM-5 eliminated the multiaxial system. Previously, Axis II included:", options:["All clinical disorders such as mood disorders, anxiety disorders, and psychotic spectrum conditions","Personality Disorders and Intellectual Disability as separate from major Axis I clinical conditions","All general medical conditions relevant to the individual's mental health treatment presentation","All psychosocial stressors and environmental problems affecting the individual's clinical condition"], answer:1, difficulty:"easy", rationale:"Correct: (B) DSM-IV Axis II: Personality Disorders and Mental Retardation (now Intellectual Disability). DSM-5 eliminated axes — all diagnoses are listed together.\n\nWhy others are wrong:\n(A) Clinical disorders were Axis I.\n(C) Medical conditions were Axis III.\n(D) Psychosocial stressors were Axis IV."},
        {domainId:7, q:"Acute Stress Disorder differs from PTSD mainly in:", options:["The type of symptoms experienced, which are completely different between these two traumatic stress diagnoses","Duration — ASD lasts from three days to one month after trauma, while PTSD is diagnosed after one month","The overall severity of symptoms, with ASD being significantly more severe than PTSD in all cases","The impossibility of ASD ever transitioning or progressing into a PTSD diagnosis over extended time"], answer:1, difficulty:"easy", rationale:"Correct: (B) ASD: 3 days to 1 month after the trauma. If symptoms persist beyond 1 month → diagnosis changes to PTSD. About 50% of ASD cases develop into PTSD.\n\nWhy others are wrong:\n(A) Symptoms overlap significantly — duration is the primary distinction.\n(C) Both can be severe.\n(D) ASD frequently transitions to PTSD."},
        {domainId:7, q:"Pica involves:", options:["Severely restrictive eating patterns with avoidance of specific food textures, colors, or sensory properties","Persistent eating of non-nutritive, non-food substances such as paint, dirt, chalk, or hair for one month","Excessive binge eating of large quantities of food with subjective loss of control over eating behavior","Only repetitive regurgitation of previously swallowed food without any other feeding or eating disturbance"], answer:1, difficulty:"easy", rationale:"Correct: (B) Pica: persistent eating of non-nutritive/non-food materials for ≥1 month, outside cultural norms and inappropriate for developmental level. Common substances: dirt, ice, starch, hair.\n\nWhy others are wrong:\n(A) Restrictive eating → ARFID or AN.\n(C) Excessive eating of food → BED.\n(D) Regurgitation → Rumination Disorder."},
        {domainId:7, q:"Obsessions in OCD are:", options:["The repetitive compulsive behaviors or mental acts performed in response to intrusive anxiety-provoking thoughts","Recurrent, intrusive, unwanted thoughts, images, or urges that cause marked distress and anxiety","Thoughts that are always immediately and fully acted upon without any resistance or suppression attempts","Exclusively focused on a single theme of contamination without encompassing any other obsessional content"], answer:1, difficulty:"easy", rationale:"Correct: (B) Obsessions: intrusive, unwanted, repetitive thoughts/images/urges that cause distress. Common themes: contamination, doubting, symmetry, forbidden thoughts, harm.\n\nWhy others are wrong:\n(A) Compulsions are the repetitive BEHAVIORS performed in response to obsessions.\n(C) Many obsessions are ego-dystonic — the person resists acting on them.\n(D) Obsessions span many themes beyond contamination."},
        {domainId:7, q:"Schizoaffective Disorder requires:", options:["Only mood symptoms without any concurrent psychotic features present during the illness duration","A period of psychotic symptoms WITHOUT mood symptoms plus periods where psychotic and mood symptoms co-occur","Only psychotic symptoms without any mood disturbance present at any point during the illness course","Only anxiety symptoms as the primary clinical feature without psychotic or mood symptom involvement"], answer:1, difficulty:"hard", rationale:"Correct: (B) Schizoaffective Disorder: major mood episode co-occurring with schizophrenia criterion A symptoms. PLUS ≥2 weeks of delusions/hallucinations WITHOUT mood symptoms. This distinguishes it from Mood Disorders with Psychotic Features.\n\nWhy others are wrong:\n(A) It requires both mood AND psychotic symptoms.\n(C) Mood symptoms must also be present for a substantial portion.\n(D) Anxiety is not the primary feature."},
        {domainId:7, q:"Bulimia Nervosa requires binge eating followed by:", options:["No compensatory behaviors of any kind following the binge eating episodes throughout the illness course","Inappropriate compensatory behaviors such as purging, fasting, or excessive exercise weekly for three months","Only excessive physical exercise as the sole compensatory method without any other purging strategies","Only psychotherapy sessions as the required intervention without any specific diagnostic behavioral criteria"], answer:1, difficulty:"easy", rationale:"Correct: (B) BN: recurrent binge eating + compensatory behaviors (vomiting, laxatives, fasting, exercise) ≥1×/week for 3 months. Self-evaluation unduly influenced by body shape/weight.\n\nWhy others are wrong:\n(A) Compensatory behaviors are required for BN diagnosis.\n(C) Multiple compensatory methods can be used.\n(D) Therapy is treatment, not a diagnostic criterion."},
        {domainId:7, q:"Social Anxiety Disorder requires fear of:", options:["Only public speaking performance situations without anxiety about any other social interaction contexts","One or more social situations in which the individual is exposed to possible scrutiny by other people","Being alone and isolated from others without any fear of social interaction or evaluation by others","Only being present in large dense crowds without any concern about individual social evaluation or scrutiny"], answer:1, difficulty:"easy", rationale:"Correct: (B) SAD: marked fear/anxiety about ≥1 social situations involving potential scrutiny. Duration ≥6 months.\n\nWhy others are wrong:\n(A) While public speaking is common, SAD can involve any social situation.\n(C) Fear of being alone → not SAD.\n(D) SAD involves scrutiny by others, not just being in crowds."},
        {domainId:7, q:"The specifier 'with limited prosocial emotions' in Conduct Disorder refers to:", options:["Excessive empathy and prosocial behavior that is developmentally inappropriate for the child's age","Callous-unemotional traits including lack of remorse, shallow affect, and deficient empathy responses","Exceptionally high social skills and advanced interpersonal competence relative to same-age peers","Only academic learning difficulties and educational underachievement without any behavioral symptom criteria"], answer:1, difficulty:"medium", rationale:"Correct: (B) CU traits: callous (lacking empathy/guilt), unemotional (shallow/deficient affect), uncaring (unconcerned about performance). Predicts more severe conduct problems and greater risk for adult ASPD.\n\nWhy others are wrong:\n(A) CU traits involve LACK of empathy.\n(C) They involve deficient social-emotional processing, not high social skills.\n(D) CU traits are about emotional/interpersonal functioning, not academics."},
        {domainId:7, q:"Shared Psychotic Disorder (folie à deux) in DSM-5:", options:["Remains a fully separate and distinct diagnostic category with its own specific diagnostic criteria","Is no longer a separate diagnosis — captured under Delusional Disorder or Other Specified Schizophrenia Spectrum","Was never a recognized concept in any edition of the DSM or international psychiatric classification systems","Can only occur between monozygotic twins and cannot develop in any other type of close relationship"], answer:1, difficulty:"hard", rationale:"Correct: (B) DSM-5 eliminated Shared Psychotic Disorder as a separate diagnosis. When a person develops delusions in the context of a close relationship with someone who has delusional disorder, it's coded as Delusional Disorder or Other Specified.\n\nWhy others are wrong:\n(A) It was removed as a stand-alone diagnosis.\n(C) It was a recognized concept in DSM-IV.\n(D) It can occur in any close relationship, not just twins."},

        // === Treatment (10) ===
        {domainId:6, q:"Interpersonal effectiveness skills in DBT include:", options:["Avoiding all interpersonal interactions and withdrawing completely from social situations as a coping strategy","DEAR MAN for making requests, GIVE for maintaining relationships, and FAST for maintaining self-respect","Only aggressive angry communication styles designed to forcefully assert one's needs over others' boundaries","Completely ignoring other people's needs and perspectives while focusing exclusively on personal emotional goals"], answer:1, difficulty:"medium", rationale:"Correct: (B) DBT interpersonal skills: DEAR MAN (Describe, Express, Assert, Reinforce, Mindful, Appear confident, Negotiate), GIVE (Gentle, Interested, Validate, Easy manner), FAST (Fair, no unnecessary Apologies, Stick to values, Truthful).\n\nWhy others are wrong:\n(A) DBT teaches engagement, not avoidance.\n(C) Effective communication involves assertiveness, not aggression.\n(D) DBT balances self-respect with relationship maintenance."},
        {domainId:6, q:"In classical conditioning, extinction occurs when:", options:["The organism physically dies ending all conditioned and unconditioned behavioral response patterns permanently","The CS is repeatedly presented WITHOUT the US leading to gradual reduction of the conditioned response","The US is presented repeatedly without the CS which does not affect the existing conditioned association","Operant punishment procedures are applied to suppress the previously conditioned behavioral response pattern"], answer:1, difficulty:"easy", rationale:"Correct: (B) Extinction: the CS is presented repeatedly without the US. The CR gradually weakens. Important: extinction doesn't erase the association — spontaneous recovery demonstrates the original learning persists.\n\nWhy others are wrong:\n(A) Extinction is about response reduction, not death.\n(C) Presenting the US without CS doesn't affect the conditioned association.\n(D) Punishment is an operant concept, not classical conditioning."},
        {domainId:6, q:"Values clarification in ACT helps clients:", options:["Judge and evaluate their personal values as objectively right or wrong based on external moral standards","Identify what matters most to them and use values as a compass for committed meaningful action","Adopt and internalize the therapist's personal values and worldview as a replacement for their own","Avoid all difficult decisions and emotionally challenging life choices by deferring to external authority"], answer:1, difficulty:"easy", rationale:"Correct: (B) ACT values work: values are freely chosen directions (not goals to achieve) that give life meaning. Values clarify WHAT direction to go; committed action is the steps taken in that direction.\n\nWhy others are wrong:\n(A) Values in ACT are not judged — they're explored.\n(C) The client identifies their OWN values, not the therapist's.\n(D) Values help GUIDE decisions rather than avoid them."},
        {domainId:6, q:"Regression in psychoanalytic theory refers to:", options:["Statistical regression to the mean which is a methodological artifact unrelated to psychoanalytic theory","Returning to an earlier developmental stage or mode of functioning when under significant psychological stress","Moving forward through developmental stages in an accelerated progression of psychological maturation","Learning entirely new adaptive skills and coping strategies that were not present at earlier developmental stages"], answer:1, difficulty:"easy", rationale:"Correct: (B) Regression (defense mechanism): reverting to behaviors/coping strategies from an earlier developmental stage when current stress overwhelms mature coping.\n\nWhy others are wrong:\n(A) Statistical regression to the mean is a different concept.\n(C) Moving forward = progression/development.\n(D) Learning new skills = growth, not regression."},
        {domainId:6, q:"Therapeutic alliance rupture and repair involves:", options:["Immediately ending therapy permanently upon the first sign of any disagreement or relational tension","Recognizing breakdowns in the alliance, addressing them directly, and restoring collaborative engagement","Completely ignoring all expressions of client dissatisfaction and continuing with the original treatment plan","Only attributing all alliance problems to the client's pathology without any therapist self-reflection needed"], answer:1, difficulty:"medium", rationale:"Correct: (B) Safran & Muran: alliance ruptures are inevitable and clinically important. Addressing them can deepen the therapeutic relationship and model healthy relational repair.\n\nWhy others are wrong:\n(A) Ruptures are opportunities, not reasons to terminate.\n(C) Ignoring ruptures allows them to worsen.\n(D) Both therapist and client contribute to ruptures."},
        {domainId:6, q:"Psychoeducation is:", options:["An intervention designed exclusively for academic students in educational settings without clinical application","Teaching clients and families about conditions, treatment options, and coping strategies as therapeutic intervention","An unnecessary and outdated component of therapy that has no empirical support for improving clinical outcomes","A training approach designed only for psychologists-in-training without any applicability to direct client care"], answer:1, difficulty:"easy", rationale:"Correct: (B) Psychoeducation: an evidence-based component providing information about the condition, treatment rationale, coping strategies, and relapse prevention. Empowers clients and reduces stigma.\n\nWhy others are wrong:\n(A) Psychoeducation is for clients and families, not just students.\n(C) Psychoeducation is one of the most effective common elements across therapies.\n(D) It's a therapeutic intervention, not just professional training."},
        {domainId:6, q:"The Gottman method for couples therapy focuses on:", options:["Only conflict resolution techniques without attention to friendship building or shared meaning creation","Building friendship, managing conflict, creating shared meaning, and identifying the Four Horsemen patterns","Dream interpretation and analysis of unconscious symbolic content within the couple's relationship dynamics","Individual insight-oriented therapy conducted separately with each partner without any conjoint sessions"], answer:1, difficulty:"medium", rationale:"Correct: (B) Gottman: research-based approach. Four Horsemen predict divorce: Criticism, Contempt, Defensiveness, Stonewalling. Couples learn antidotes to each.\n\nWhy others are wrong:\n(A) Friendship building and shared meaning are equally important.\n(C) Not psychoanalytic.\n(D) It's a couples approach, not individual therapy."},
        {domainId:6, q:"The therapeutic use of homework in CBT serves to:", options:["Punish the client for slow progress by assigning additional burdensome tasks outside of therapy sessions","Help clients practice skills, test beliefs, and generalize learning from therapy sessions to everyday life","Give the therapist a break from the demands of active in-session clinical engagement with the client","Only fill unstructured time between sessions without serving any specific therapeutic or clinical purpose"], answer:1, difficulty:"easy", rationale:"Correct: (B) CBT homework: essential for generalization. Activities include thought records, behavioral experiments, activity scheduling, exposure exercises. Homework completion is associated with better outcomes.\n\nWhy others are wrong:\n(A) Homework is collaborative and therapeutic, not punitive.\n(C) The therapist is actively involved in designing meaningful homework.\n(D) Homework is a core active ingredient of CBT."},
        {domainId:6, q:"De-escalation techniques in crisis situations include:", options:["Yelling louder than the agitated client to establish authority dominance and regain control of the situation","Calm tone, active listening, validating emotions, creating physical space, and avoiding unnecessary power struggles","Being deliberately confrontational and provocative to force an immediate resolution of the crisis situation","Immediately applying physical restraints as the first response before attempting any verbal intervention techniques"], answer:1, difficulty:"easy", rationale:"Correct: (B) De-escalation: calm voice, empathic validation, open body language, respectful distance, offering choices. Physical intervention is a LAST resort.\n\nWhy others are wrong:\n(A) Matching escalation worsens the situation.\n(C) Confrontation increases agitation.\n(D) Physical intervention is the last resort, not first response."},
        {domainId:6, q:"Telehealth has been shown by research to be:", options:["Significantly less effective than in-person therapy for all clinical conditions across every treatment population","Comparably effective to in-person therapy for many conditions with advantages in access and convenience","Completely untested with no empirical research evidence available regarding its clinical effectiveness outcomes","Only effective for medication management and not for any form of psychotherapy or behavioral intervention"], answer:1, difficulty:"easy", rationale:"Correct: (B) Meta-analyses show telehealth psychotherapy is comparably effective to in-person for depression, anxiety, PTSD. Advantages: increased access, convenience, reduced stigma.\n\nWhy others are wrong:\n(A) Research generally supports comparable effectiveness.\n(C) Extensive research exists, especially post-COVID.\n(D) Telehealth supports a full range of interventions."},

        // === Bio/Research/Cognitive/Development/Social (20) ===
        {domainId:1, q:"The substantia nigra is primarily associated with:", options:["Language processing mediated by Broca's and Wernicke's cortical areas in the dominant hemisphere","Dopamine production for the nigrostriatal pathway whose degeneration causes Parkinson's Disease","Visual perception mediated by the primary visual cortex located within the occipital lobe region","Auditory perception mediated by the auditory cortex located within the temporal lobe region"], answer:1, difficulty:"medium", rationale:"Correct: (B) Substantia nigra: dopaminergic neurons projecting to the striatum (nigrostriatal pathway). Degeneration → Parkinson's Disease (tremor, rigidity, bradykinesia). Treated with L-DOPA.\n\nWhy others are wrong:\n(A) Language → Broca's and Wernicke's areas.\n(C) Vision → occipital cortex.\n(D) Hearing → auditory cortex (temporal lobe)."},
        {domainId:1, q:"A factorial design in research involves:", options:["Only one single independent variable manipulated across two or more levels of that variable","Two or more independent variables studied simultaneously to examine both main effects AND interactions","Only qualitative phenomenological methods without any quantitative measurement or statistical analysis","No statistical analysis of any kind with results interpreted through purely narrative description"], answer:1, difficulty:"medium", rationale:"Correct: (B) Factorial design: ≥2 IVs with all combinations of levels. Allows examination of main effects (each IV separately) AND interactions (combined effects).\n\nWhy others are wrong:\n(A) One IV = a single-factor design, not factorial.\n(C) Factorial designs are quantitative/experimental.\n(D) Factorial designs use ANOVA and other statistical tests."},
        {domainId:1, q:"External validity refers to:", options:["The internal consistency reliability of a psychometric test measuring item-level intercorrelation","The degree to which research findings can be generalized to other populations, settings, and times","Only laboratory experiments conducted in tightly controlled artificial environmental research conditions","Statistical significance indicating the probability of obtaining results by chance under the null hypothesis"], answer:1, difficulty:"easy", rationale:"Correct: (B) External validity: generalizability of findings beyond the specific study sample, setting, and conditions. Enhanced by diverse samples, real-world settings, and replication.\n\nWhy others are wrong:\n(A) Internal consistency → reliability.\n(C) Lab experiments tend to have LOWER external validity.\n(D) Statistical significance is about probability, not generalizability."},
        {domainId:1, q:"The ventral tegmental area (VTA) is part of:", options:["The visual system processing retinal input through the lateral geniculate nucleus of the thalamus","The mesolimbic dopamine pathway functioning as the brain's primary reward and motivation system","The auditory system processing sound information through the medial geniculate nucleus of the thalamus","The somatosensory system processing tactile information through the ventral posterolateral thalamic nucleus"], answer:1, difficulty:"medium", rationale:"Correct: (B) VTA → nucleus accumbens (mesolimbic pathway): the brain's reward circuit. Activated by natural rewards and addictive substances. Dysregulation → substance use disorders, anhedonia.\n\nWhy others are wrong:\n(A)(C)(D) The VTA is part of the dopaminergic reward system, not sensory pathways."},
        {domainId:2, q:"Confirmation bias is the tendency to:", options:["Actively seek disconfirming evidence that contradicts one's pre-existing beliefs and current hypotheses","Search for, interpret, and remember information in a way that confirms one's pre-existing beliefs","Maintain complete objectivity in all situations without any influence from prior expectations or beliefs","Change one's beliefs easily and rapidly whenever any new contradictory information is encountered"], answer:1, difficulty:"easy", rationale:"Correct: (B) Confirmation bias: seeking/interpreting information to support existing beliefs while dismissing contradictory evidence. One of the most pervasive cognitive biases.\n\nWhy others are wrong:\n(A) Seeking disconfirming evidence is scientific thinking — the OPPOSITE.\n(C) Confirmation bias makes objectivity difficult.\n(D) Confirmation bias REINFORCES existing beliefs, making change harder."},
        {domainId:2, q:"The flashbulb memory concept (Brown & Kulik) suggests that:", options:["All memories are encoded with equally vivid detail regardless of the emotional content of the event","Highly emotional events create exceptionally vivid memories though research shows they may not be more accurate","Human memory works exactly like a camera producing perfectly accurate photographic reproductions of events","Emotional events are forgotten significantly faster than neutral events due to interference from arousal"], answer:1, difficulty:"medium", rationale:"Correct: (B) Flashbulb memories: people feel memories of surprising, emotional events are extremely vivid and accurate. However, research shows these memories are confident but not necessarily more accurate.\n\nWhy others are wrong:\n(A) Flashbulb memories are distinctively vivid compared to routine memories.\n(C) Memory is reconstructive, not photographic.\n(D) Emotional events are generally remembered BETTER, though with potential distortions."},
        {domainId:4, q:"Ainsworth's Strange Situation assesses:", options:["General intelligence and cognitive ability through standardized developmental assessment procedures","Attachment quality in infants through systematic separations and reunions with the caregiver and stranger","Academic readiness and pre-literacy skills needed for successful kindergarten entry and school adjustment","Language development milestones including expressive and receptive vocabulary in early childhood toddlers"], answer:1, difficulty:"easy", rationale:"Correct: (B) The Strange Situation (12-18 months): 8 episodes involving the infant, caregiver, and stranger. Reunion behavior is the primary classification criterion.\n\nWhy others are wrong:\n(A) Intelligence → Bayley Scales.\n(C) Academic readiness → school readiness assessments.\n(D) Language → language assessments."},
        {domainId:4, q:"Vygotsky differed from Piaget primarily in emphasizing:", options:["Individual biological maturation as the sole driver of cognitive development without social influence","The role of social interaction, culture, and language as primary drivers of cognitive development","Only biological genetic factors as determinants of cognitive growth without environmental contributions","Fixed universal developmental stages that all children progress through in an invariant sequential order"], answer:1, difficulty:"easy", rationale:"Correct: (B) Vygotsky: cognitive development is fundamentally a SOCIAL process. Children learn through guided participation with more knowledgeable others (MKOs).\n\nWhy others are wrong:\n(A) Individual maturation → more aligned with Piaget.\n(C) Vygotsky emphasized sociocultural factors, not just biology.\n(D) Vygotsky didn't propose fixed stages like Piaget."},
        {domainId:3, q:"Conformity research (Asch) shows that:", options:["People virtually never conform to group pressure and always maintain their independent accurate judgments","A significant percentage of participants conformed to clearly incorrect group consensus when unanimous","Conformity only occurs under conditions of direct physical threat or coercion from authority figures","Only children conform to group pressure while adults consistently maintain independent accurate judgments"], answer:1, difficulty:"easy", rationale:"Correct: (B) Asch: ~75% conformed at least once to obviously wrong answers facing a unanimous majority. Factors: group size, unanimity, public responding.\n\nWhy others are wrong:\n(A) Conformity was substantial and consistent.\n(C) No physical threat was present — pure social pressure.\n(D) Adults conformed readily."},
        {domainId:3, q:"The just-world hypothesis (Lerner) contributes to:", options:["Perfect justice and equitable treatment of all individuals across every social and institutional context","Victim blaming through the belief that people get what they deserve leading to blaming victims' character","Scientific objectivity by providing an unbiased framework for understanding social inequality and suffering","Social activism and advocacy by motivating individuals to work toward correcting systemic injustices"], answer:1, difficulty:"medium", rationale:"Correct: (B) Just-world belief: people need to believe the world is fair. When innocent people suffer, this creates cognitive dissonance → resolved by blaming the victim.\n\nWhy others are wrong:\n(A) The just-world belief is a cognitive bias, not actual justice.\n(C) It undermines objectivity by introducing motivated reasoning.\n(D) Just-world beliefs may actually reduce motivation for social change."},
        {domainId:3, q:"Obedience research (Milgram) demonstrated that:", options:["Virtually no participants obeyed authority instructions to administer harmful actions to another person","A majority of participants obeyed instructions to administer seemingly dangerous shocks when ordered","Only individuals with sadistic personality traits obeyed harmful orders from the authority figure present","Authority figures have absolutely no measurable influence on the behavior of ordinary research participants"], answer:1, difficulty:"easy", rationale:"Correct: (B) Milgram: ~65% delivered maximum 'shocks' (450V) when ordered. Key factors: authority legitimacy, gradual escalation, proximity effects, agentic state.\n\nWhy others are wrong:\n(A) Obedience rates were alarmingly high.\n(C) Participants were ordinary people — situational factors were key.\n(D) Authority profoundly influenced behavior."},
        {domainId:2, q:"Interference theory of forgetting distinguishes between:", options:["Only one single type of forgetting mechanism without any further differentiation or subcategories","Proactive interference where old learning blocks new and retroactive interference where new blocks old","Memory traces that never existed in the first place and cannot be retrieved under any conditions","Only motivated repression of emotionally distressing content without any automatic interference processes"], answer:1, difficulty:"easy", rationale:"Correct: (B) Proactive: old disrupts new. Retroactive: new disrupts old. Both are well-established forgetting mechanisms.\n\nWhy others are wrong:\n(A) Two distinct types of interference exist.\n(C) Interference affects existing memories, not nonexistent ones.\n(D) Interference is automatic, not motivated."},
        {domainId:2, q:"The representativeness heuristic leads to:", options:["Always correct and accurate probability judgments in every decision-making context and situation","Judging probability by similarity to a prototype which can lead to base rate neglect and conjunction fallacy","Perfect statistical reasoning that consistently produces optimal Bayesian probability estimates and updates","Successfully avoiding all cognitive heuristics entirely and relying only on formal logical analysis methods"], answer:1, difficulty:"medium", rationale:"Correct: (B) Representativeness heuristic (Tversky & Kahneman): judging probability by similarity to a mental prototype. Errors: ignoring base rates, conjunction fallacy.\n\nWhy others are wrong:\n(A) Heuristics often lead to systematic errors.\n(C) Heuristics are mental shortcuts that bypass statistical reasoning.\n(D) Everyone uses heuristics — they can't be entirely avoided."},
        {domainId:1, q:"Randomized controlled trials (RCTs) are considered the gold standard because:", options:["They are the easiest and least resource-intensive research designs to conduct in clinical settings","Random assignment to conditions controls for confounding variables thereby allowing causal inferences","They do not require any control groups or comparison conditions to produce valid interpretable results","They rely exclusively on qualitative data collection methods without any quantitative measurement tools"], answer:1, difficulty:"easy", rationale:"Correct: (B) RCTs: random assignment distributes known AND unknown confounds equally across conditions, isolating the IV's causal effect.\n\nWhy others are wrong:\n(A) RCTs are typically MORE resource-intensive than other designs.\n(C) Control groups are essential to RCTs.\n(D) RCTs are quantitative designs."},
        {domainId:4, q:"Developmental milestones for walking typically occur around:", options:["Three months of age when infants are primarily developing basic head control and visual tracking","Twelve months of age with a normal developmental range spanning approximately nine to fifteen months","Twenty-four months of age when children are already well established in walking and beginning to run","Thirty-six months of age when children have already developed advanced gross motor skills like jumping"], answer:1, difficulty:"easy", rationale:"Correct: (B) Most children take first independent steps around 12 months (range: 9-15 months).\n\nWhy others are wrong:\n(A) At 3 months, infants are developing head control.\n(C) By 24 months, walking is well established; running begins.\n(D) By 36 months, children can pedal, jump, and climb stairs."},
        {domainId:1, q:"Selection bias threatens internal validity when:", options:["Random assignment procedures are properly used to equalize participant characteristics across conditions","Groups being compared differ systematically BEFORE the treatment is introduced creating confounded results","The study utilizes a large and representative sample that adequately represents the target population","Double-blind procedures and participant blinding are correctly implemented throughout the entire study"], answer:1, difficulty:"easy", rationale:"Correct: (B) Selection bias: pre-existing differences between groups could explain outcome differences. Random assignment is the primary defense.\n\nWhy others are wrong:\n(A) Random assignment PREVENTS selection bias.\n(C) Large samples don't eliminate selection bias without randomization.\n(D) Blinding controls for experimenter/participant bias, not selection bias."},
        {domainId:1, q:"Regression to the mean occurs when:", options:["All participants in a study improve equally regardless of their initial baseline scores on the measure","Extreme scores on one measurement tend to be less extreme on subsequent measurements without intervention","Test scores never change across repeated administrations and remain perfectly stable over extended periods","Only treatment group participants show measurable change while control group scores remain completely stable"], answer:1, difficulty:"medium", rationale:"Correct: (B) Regression to the mean: extreme scores contain true score and error. On retesting, error is unlikely to be equally extreme → scores move toward the mean.\n\nWhy others are wrong:\n(A) Improvement is not uniform — extreme scorers change more.\n(C) Scores do change, particularly extreme ones.\n(D) Both treatment and control groups are affected."},
        {domainId:3, q:"Attribution theory (Weiner) classifies causes of behavior along three dimensions:", options:["Only the single dimension of internal versus external locus of causality without further differentiation","Locus of causality, stability over time, and controllability of the causal factor being considered","Only temporal dimensions of past, present, and future without considering any causal structural properties","Only evaluative dimensions of positive and negative valence without considering causal structural features"], answer:1, difficulty:"medium", rationale:"Correct: (B) Weiner: (1) Locus — internal vs. external. (2) Stability — stable vs. unstable. (3) Controllability — controllable vs. uncontrollable. These predict emotional reactions and future expectations.\n\nWhy others are wrong:\n(A) Weiner expanded beyond the simple internal/external distinction.\n(C) These aren't temporal dimensions.\n(D) The dimensions describe causal structure, not valence."},
        {domainId:2, q:"Metacognition refers to:", options:["Memory for factual semantic knowledge stored in long-term declarative memory retrieval systems","Thinking about thinking — awareness and regulation of one's own cognitive processes and strategies","Only emotional awareness and affect regulation without any involvement of higher-order cognitive monitoring","A type of functional neuroimaging brain scanning technology used in cognitive neuroscience research"], answer:1, difficulty:"easy", rationale:"Correct: (B) Metacognition: knowledge about one's own cognitive processes and the ability to monitor and regulate them. Related to academic success.\n\nWhy others are wrong:\n(A) Memory for facts = semantic memory.\n(C) Emotional awareness is one component but not the whole concept.\n(D) Brain imaging is a research method, not a cognitive process."}
    ];

    batch48.forEach(q => {
        const domain = EPPPData.domains.find(d => d.id === q.domainId);
        if (domain) {
            domain.questions.push({
                q: q.q, options: q.options, answer: q.answer,
                difficulty: q.difficulty, rationale: q.rationale,
                domainId: q.domainId, domainName: domain.name
            });
        }
    });

    console.log(`PasstheEPPP: Loaded ${batch48.length} additional questions (batch 48).`);
})();
